192→export const deleteNotificationService = async (userId, notifId, source) => {
193→    if (!notifId) {
194→        throw { status: 400, error: 'notifId is required' };
195→    }
196→
197→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
198→
199→    const { error } = await supabase
200→        .from(tableName)
201→        .delete()
202→        .eq('receiver_id', userId)
203→        .eq('id', notifId);
204→
205→    if (error) {
206→        console.error('supabase error while deleting notification:', error.message);
207→        throw { status: 500, error: 'supabase error while deleting notification' };
208→    }
209→
210→    return { message: 'success' };
211→};
