13→const parseLimitOrFail = (raw, res) => {
14→    const parsed = parseLimitWithinRange(raw, NOTIFICATION_LIMIT_MIN, NOTIFICATION_LIMIT_MAX, NOTIFICATION_DEFAULT_LIMIT);
15→    if (parsed == null) {
16→        res.status(400).json({ error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}` });
17→        return null;
18→    }
19→    return parsed;
20→};
