128→                            </motion.div>
129→                        )}
130→                    </AnimatePresence>
131→
132→                    {hasRecap && hasPrompt && !recapCollapsed && (
133→                        <div className="dashboard-divider" />
134→                    )}
135→
136→                    {hasPrompt && (
137→                        <PromptSection
138→                            prompt={prompt}
139→                            responsesData={responsesData}
140→                            onWriteResponse={onWriteResponse}
141→                        />
142→                    )}
143→                </div>
144→            </motion.div>
145→        </AnimatePresence>
146→    );
147→};
