241→                const displayType = isOpinion ? 'opinion_reply' : notification?.type;
242→                const previewText = !isOpinion ? (notification?.journals?.preview_text || '') : '';
243→                const thumbnailUrl = !isOpinion ? (notification?.journals?.thumbnail_url || null) : null;
244→
245→                return(
246→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
247→
248→                    <div className="notification-cards-child-container">
