43→                                        r.users?.badge === 'legend' ? ' pr-ring-legend' :
44→                                        r.users?.badge === 'og' ? ' pr-ring-og' : ''
45→                                    }`}
46→                                    style={{ zIndex: avatars.length - i }}
47→                                >
48→                                    <img
49→                                        src={r.users?.image_url || '/assets/profile.jpg'}
50→                                        alt=""
51→                                        className="dashboard-prompt-avatar"
52→                                    />
53→                                </div>
54→                            ))}
55→                        </div>
56→                        <span className="dashboard-prompt-count">
57→                            {responseCount} {responseCount === 1 ? 'response' : 'responses'}
58→                        </span>
59→                    </div>
60→                )}
61→            </div>
62→
63→            {showModal && (
64→                <PromptResponsesModal
65→                    promptId={prompt.id}
66→                    count={responseCount}
67→                    promptText={prompt.prompt_text}
68→                    onClose={() => setShowModal(false)}
69→                />
70→            )}
71→        </div>
72→    );
73→};
74→
75→export default PromptSection;
